/** Single list: MV characteristics with icons only (no duplicate text-only list). */
const PropertyCharacteristics: React.FC<{ property: PropertySearchCardData }> = ({ property }) => {
  const attrs = property.dynamicAttributes;
  const iconItems: Array<{ show: boolean; label: string; icon: React.ReactNode }> = [
    { show: hasTerrainSurface(attrs), label: `Terrain : ${attrs?.['Terrain'] ?? ''}`, icon: <TerrainIcon /> },
    { show: hasAttr(attrs, 'Piscine'), label: 'Piscine', icon: <PiscineIcon /> },
    { show: hasAttr(attrs, 'Meublé'), label: 'Meublé', icon: <MeubleIcon /> },
    { show: hasAttr(attrs, 'Terrasse'), label: 'Terrasse', icon: <TerrasseIcon /> },
    { show: hasAttr(attrs, 'Balcon'), label: 'Balcon', icon: <BalconIcon /> },
    { show: hasAttr(attrs, 'Cave'), label: 'Cave', icon: <CaveIcon /> },
    { show: hasAttr(attrs, 'Jardin'), label: 'Jardin', icon: <JardinIcon /> },
    { show: hasAttr(attrs, 'Parking'), label: 'Parking', icon: <ParkingIcon /> },
    { show: hasAttr(attrs, 'Étage'), label: `Étage : ${attrs?.['Étage'] ?? ''}`, icon: <EtageIcon /> },
  ];

  return (
    <motion.div
      className="mt-3 flex flex-wrap items-center gap-2 text-xs text-gray-500"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.3, delay: 0.65 }}
    >
      {iconItems
        .filter(item => item.show)
        .map((item, i) => (
          <div key={`icon-${item.label}-${i}`} className="flex items-center gap-1.5">
            {item.icon}
            <span>{item.label}</span>
          </div>
        ))}
    </motion.div>
  );
};

export const PropertySearchCard: React.FC<PropertySearchCardProps> = ({
  property,
  index,
  mode,
  associationDisplayNames,
  ImageGallery,
  priceLabel,
  priceSuffix,
}) => {
  const pricePerSqm = getPricePerSqm(property.price, property.surface);
  const energyLetter = getEnergyClassLetter(property.dynamicAttributes);

  return (
    <motion.div
      className="relative bg-white rounded-3xl p-3 shadow-md overflow-visible"
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: index * 0.1 }}
      whileHover={{ y: -5, boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)' }}
    >
      <div className="relative">
        <ImageGallery images={property.images} tags={property.tags} minimalOverlay />
        {energyLetter && <EnergyClassBadge letter={energyLetter} />}
      </div>

      <div className="p-4">
        <motion.div className="flex justify-between items-start" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.3, delay: 0.3 }}>
          <div className="flex-1">
            <div className="flex items-center gap-3">
              <motion.h2 className="text-xl font-bold text-gray-900" whileHover={{ scale: 1.05 }}>
                <span className="text-lg font-normal text-gray-600">{priceLabel}</span>{' '}
                {property.price.replace(/[€*]/g, '').replace(/\s{2,}/g, ' ').trim()}
                {priceSuffix}
              </motion.h2>
              {pricePerSqm && <span className="text-sm text-gray-600">{pricePerSqm}</span>}
            </div>
          </div>
        </motion.div>

        <motion.div className="mt-2 flex flex-wrap items-center gap-x-2 gap-y-1 text-sm" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.3, delay: 0.4 }}>
          <span className="font-semibold" style={getTypeTextStyle(property.type)}>
            {property.type}
          </span>
          {(() => {
            const hasRoom = property.rooms && property.rooms !== 'N/A';
            const hasChambre = property.chambres && property.chambres !== 'N/A';
            const hasSurface = property.surface && property.surface !== 'N/A';
            const parts = [
              hasRoom && (/pièce/i.test(property.rooms) ? property.rooms : `${property.rooms} pièces`),
              hasChambre && (/chambre/i.test(property.chambres) ? property.chambres : `${property.chambres} Chambres`),
              hasSurface && property.surface,
            ].filter(Boolean);
            return parts.length > 0 ? (
              <span className="text-gray-500">{parts.join(' · ')}</span>
            ) : null;
          })()}
        </motion.div>

        <PropertyCharacteristics property={property} />

        {property.description?.trim() && (
          <motion.p
            className="text-gray-500 text-xs mt-2 line-clamp-1"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.3, delay: 0.55 }}
          >
            {property.description}
          </motion.p>
        )}

        <motion.div className="mt-3 flex items-center text-xs text-gray-500" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.3, delay: 0.7 }}>
          <span className="font-bold text-gray-600 mr-1.5 underline">Adresse Exacte</span>
          <svg className="h-4 w-4 mr-1 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          {property.address}
        </motion.div>

        <motion.div className="mt-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.3, delay: 0.8 }}>
          <span className="text-xs font-bold text-gray-600 block mb-2 underline">Liens vers l'annonce</span>
          <div className="flex items-center space-x-2">
            {property.Association.map((assoc, assocIndex) => (
              <motion.a
                key={assocIndex}
                href={property.Association_url[assocIndex]}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center space-x-1 text-sm text-gray-600 hover:text-gray-900"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                <img src={ASSOCIATION_LOGOS[assoc] || ASSOCIATION_LOGOS.seloger} alt={assoc} className="h-4 w-4 object-contain" />
                <span>{associationDisplayNames[assoc] || assoc}</span>
              </motion.a>
            ))}
          </div>
        </motion.div>
      </div>
    </motion.div>
  );
};
